const base='https://services.leadconnectorhq.com';
const token=process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB||process.env.GHL_PRIVATE_INTEGRATION_TOKEN||process.env.GHL_TOKEN;
const loc=process.env.GHL_LOCATION_ID_TJB||process.env.GHL_LOCATION_ID||'TW8JsPW5NMnA3tfK2XLn';
if(!token){console.error('NO_TOKEN');process.exit(2)}
const h={Authorization:'Bearer '+token,Version:'2021-07-28','Content-Type':'application/json'};
const req=async(method,path,body)=>{
  const r=await fetch(base+path,{method,headers:h,body:body?JSON.stringify(body):undefined});
  const t=await r.text();
  let j={};
  try{j=JSON.parse(t)}catch{j={raw:t}}
  return {status:r.status,body:j};
};
(async()=>{
 const contactsR=await req('GET',`/contacts/?locationId=${loc}&limit=100`);
 const oppR=await req('POST','/opportunities/search',{locationId:loc,limit:500});
 const pipesR=await req('GET',`/opportunities/pipelines?locationId=${loc}`);
 const wfR=await req('GET',`/workflows/?locationId=${loc}`);
 const contacts=contactsR.body.contacts||[];
 const opps=oppR.body.opportunities||[];
 const pipes=(pipesR.body.pipelines||[]);
 const stageMap={};
 for(const p of pipes){for(const s of (p.stages||[])){stageMap[s.id]={pipeline:p.name,stage:s.name};}}
 const tagCount={};
 for(const c of contacts){for(const t of (c.tags||[])){tagCount[t]=(tagCount[t]||0)+1;}}
 const leads=contacts.length;
 const ebook=tagCount['ebook-buyer']||0;
 const course=tagCount['course-buyer']||0;
 const intensive=tagCount['high-ticket-prospect']||0;
 const conv={
   lead_to_ebook: leads?ebook/leads*100:0,
   ebook_to_course: ebook?course/ebook*100:0,
   course_to_high_ticket: course?intensive/course*100:0
 };
 let pipelineValue=0;
 const byStage={};
 for(const o of opps){
   const val=Number(o.monetaryValue||0);
   pipelineValue+=val;
   const sid=o.pipelineStageId||'unknown';
   if(!byStage[sid]) byStage[sid]={count:0,value:0,name:stageMap[sid]?.stage||sid,pipeline:stageMap[sid]?.pipeline||'unknown'};
   byStage[sid].count++;
   byStage[sid].value+=val;
 }
 const topStages=Object.values(byStage).sort((a,b)=>b.value-a.value);
 const emailMetricAccess=[];
 for(const p of ['/emails/campaigns?locationId='+loc,'/reporting/email?locationId='+loc,'/campaigns/?locationId='+loc]){
   const r=await fetch(base+p,{headers:h});
   emailMetricAccess.push({path:p,status:r.status});
 }
 const out={
   locationId:loc,
   instances:[{name:'Truth J Blue — Primary SaaS',locationId:loc}],
   counts:{contacts:contacts.length,opportunities:opps.length,workflows:(wfR.body.workflows||[]).length},
   tagCount,
   conversionRates:conv,
   pipelineValue,
   topStages,
   emailMetricAccess,
   timestamp:new Date().toISOString()
 };
 console.log(JSON.stringify(out,null,2));
})();

#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

const BASE = 'https://services.leadconnectorhq.com';
const TIME_ZONE = 'America/Chicago';
const ROOT_DIR = path.resolve(__dirname, '..');
const DEFAULT_LOCATION = 'TW8JsPW5NMnA3tfK2XLn';

loadEnvFile(path.join(ROOT_DIR, '.env'));

const args = parseArgs(process.argv.slice(2));
const TOKEN = args.token || process.env.GHL_PRIVATE_INTEGRATION_TOKEN || process.env.GHL_TOKEN;
const LOC = args.location || process.env.GHL_LOCATION_ID || process.env.GHL_LOCATION_ID_TJB || DEFAULT_LOCATION;
const MESSAGE_LIMIT = parsePositiveInt(args['message-limit'], 100);
const CONVERSATION_LIMIT = parsePositiveInt(args['conversation-limit'], 100);
const WINDOW_DAYS = parsePositiveInt(args['window-days'], 7);
const YESTERDAY_KEY = args.yesterday || getRelativeDateKeyInTimeZone(TIME_ZONE, -1);
const headers = {
  Authorization: `Bearer ${TOKEN}`,
  Version: '2021-07-28',
  'Content-Type': 'application/json'
};

function parseArgs(argv) {
  const out = {};
  for (let i = 0; i < argv.length; i++) {
    const item = argv[i];
    if (!item.startsWith('--')) continue;
    const key = item.slice(2);
    const next = argv[i + 1];
    out[key] = next && !next.startsWith('--') ? argv[++i] : true;
  }
  return out;
}

function parsePositiveInt(value, fallback) {
  const parsed = Number.parseInt(value, 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function loadEnvFile(filePath) {
  if (!fs.existsSync(filePath)) return;
  const contents = fs.readFileSync(filePath, 'utf8');
  for (const rawLine of contents.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line || line.startsWith('#')) continue;
    const idx = line.indexOf('=');
    if (idx === -1) continue;
    const key = line.slice(0, idx).trim();
    let value = line.slice(idx + 1).trim();
    if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }
    if (!process.env[key]) process.env[key] = value;
  }
}

function toMs(value) {
  if (value == null) return NaN;
  if (typeof value === 'number') return value < 1e12 ? value * 1000 : value;
  const parsed = Date.parse(value);
  return Number.isNaN(parsed) ? NaN : parsed;
}

function getDateParts(date, timeZone) {
  const formatter = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hourCycle: 'h23'
  });
  const parts = Object.fromEntries(formatter.formatToParts(date).map((part) => [part.type, part.value]));
  return {
    year: Number(parts.year),
    month: Number(parts.month),
    day: Number(parts.day),
    hour: Number(parts.hour),
    minute: Number(parts.minute),
    second: Number(parts.second)
  };
}

function dayKeyCT(ms) {
  return new Intl.DateTimeFormat('en-CA', {
    timeZone: TIME_ZONE,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).format(new Date(ms));
}

function getRelativeDateKeyInTimeZone(timeZone, deltaDays) {
  const now = new Date();
  const parts = getDateParts(now, timeZone);
  const pivot = new Date(Date.UTC(parts.year, parts.month - 1, parts.day + deltaDays));
  return `${pivot.getUTCFullYear()}-${String(pivot.getUTCMonth() + 1).padStart(2, '0')}-${String(pivot.getUTCDate()).padStart(2, '0')}`;
}

function addDays(dateKey, days) {
  const [year, month, day] = dateKey.split('-').map(Number);
  const pivot = new Date(Date.UTC(year, month - 1, day + days));
  return `${pivot.getUTCFullYear()}-${String(pivot.getUTCMonth() + 1).padStart(2, '0')}-${String(pivot.getUTCDate()).padStart(2, '0')}`;
}

function zonedMidnightUtc(dateKey, timeZone) {
  const [year, month, day] = dateKey.split('-').map(Number);
  const base = Date.UTC(year, month - 1, day, 0, 0, 0, 0);
  for (let offsetMinutes = -14 * 60; offsetMinutes <= 14 * 60; offsetMinutes += 15) {
    const candidate = base - offsetMinutes * 60_000;
    const parts = getDateParts(new Date(candidate), timeZone);
    if (
      parts.year === year &&
      parts.month === month &&
      parts.day === day &&
      parts.hour === 0 &&
      parts.minute === 0 &&
      parts.second === 0
    ) {
      return candidate;
    }
  }
  throw new Error(`Unable to resolve midnight for ${dateKey} in ${timeZone}`);
}

function quant(values, percentile) {
  if (!values.length) return null;
  const sorted = [...values].sort((a, b) => a - b);
  const index = Math.min(sorted.length - 1, Math.max(0, Math.ceil(percentile * sorted.length) - 1));
  return sorted[index];
}

async function req(requestPath) {
  const response = await fetch(`${BASE}${requestPath}`, { headers });
  const text = await response.text();
  let json = {};
  try {
    json = text ? JSON.parse(text) : {};
  } catch {
    json = { raw: text };
  }
  if (!response.ok) {
    throw new Error(`${requestPath} -> ${response.status} ${text.slice(0, 180)}`);
  }
  return json;
}

(async () => {
  if (!TOKEN) throw new Error('Missing GHL token. Set GHL_PRIVATE_INTEGRATION_TOKEN or pass --token.');

  const yesterdayStart = zonedMidnightUtc(YESTERDAY_KEY, TIME_ZONE);
  const yesterdayEnd = zonedMidnightUtc(addDays(YESTERDAY_KEY, 1), TIME_ZONE) - 1;
  const windowStartKey = addDays(YESTERDAY_KEY, -(WINDOW_DAYS - 1));
  const windowStart = zonedMidnightUtc(windowStartKey, TIME_ZONE);
  const windowEnd = yesterdayEnd;

  const convRes = await req(`/conversations/search?locationId=${LOC}&limit=${CONVERSATION_LIMIT}`);
  const conversations = convRes.conversations || convRes.data || [];
  const oppRes = await req(`/opportunities/search?location_id=${LOC}&limit=1`);
  const oppTotal = oppRes?.meta?.total || 0;

  const leadsByDay = {};
  let leadsYesterday = 0;
  const stale24 = conversations.filter((conversation) => {
    const last = toMs(conversation.lastMessageDate || conversation.dateUpdated || conversation.dateAdded);
    return conversation.inbox === true && Number.isFinite(last) && (Date.now() - last) > 24 * 3600 * 1000;
  }).length;

  const leadConvs = conversations.filter((conversation) => {
    const added = toMs(conversation.dateAdded);
    return Number.isFinite(added) && added >= windowStart && added <= windowEnd;
  });

  for (const conversation of leadConvs) {
    const added = toMs(conversation.dateAdded);
    const key = dayKeyCT(added);
    leadsByDay[key] = (leadsByDay[key] || 0) + 1;
    if (added >= yesterdayStart && added <= yesterdayEnd) leadsYesterday++;
  }

  const speedVals = [];
  const speedValsYesterday = [];
  let bookedCallsWindow = 0;
  let bookedCallsYesterday = 0;

  for (const conversation of leadConvs) {
    let messages = [];
    try {
      const result = await req(`/conversations/${conversation.id}/messages?limit=${MESSAGE_LIMIT}`);
      messages = result.messages || result.data || [];
    } catch {
      messages = [];
    }
    if (!messages.length) continue;

    const enriched = messages
      .map((message) => ({
        dir: (message.direction || message.messageDirection || '').toLowerCase(),
        type: (message.messageType || message.type || '').toLowerCase(),
        t: toMs(message.dateAdded || message.createdAt || message.timestamp || message.messageDate)
      }))
      .filter((entry) => Number.isFinite(entry.t))
      .sort((a, b) => a.t - b.t);

    if (!enriched.length) continue;

    const firstInbound = enriched.find((message) => message.dir === 'inbound')?.t ?? toMs(conversation.dateAdded);
    const firstOutbound = enriched.find((message) => message.dir === 'outbound')?.t;

    if (Number.isFinite(firstInbound) && Number.isFinite(firstOutbound) && firstOutbound >= firstInbound) {
      const minutes = (firstOutbound - firstInbound) / 60_000;
      if (minutes >= 0 && minutes < 60 * 24 * 14) {
        speedVals.push(minutes);
        const leadAdded = toMs(conversation.dateAdded);
        if (leadAdded >= yesterdayStart && leadAdded <= yesterdayEnd) speedValsYesterday.push(minutes);
      }
    }

    const appointmentMsgs = enriched.filter((message) => message.type.includes('appointment') || message.type.includes('calendar'));
    if (appointmentMsgs.length) {
      if (appointmentMsgs.some((message) => message.t >= windowStart && message.t <= windowEnd)) bookedCallsWindow++;
      if (appointmentMsgs.some((message) => message.t >= yesterdayStart && message.t <= yesterdayEnd)) bookedCallsYesterday++;
    }
  }

  const days = [];
  for (let i = 0; i < WINDOW_DAYS; i++) {
    days.push(addDays(windowStartKey, i));
  }

  const output = {
    metadata: {
      locationId: LOC,
      timeZone: TIME_ZONE,
      yesterdayKey: YESTERDAY_KEY,
      windowDays: WINDOW_DAYS,
      conversationLimit: CONVERSATION_LIMIT,
      messageLimit: MESSAGE_LIMIT
    },
    sampleSize: {
      conversations: conversations.length,
      leadConversationsWindow: leadConvs.length,
      opportunitiesTotal: oppTotal
    },
    yesterday: {
      bookedCalls: bookedCallsYesterday,
      leadsCreated: leadsYesterday,
      speedMedianMin: quant(speedValsYesterday, 0.5),
      speedP95Min: quant(speedValsYesterday, 0.95)
    },
    trendWindow: {
      bookedCallsTotal: bookedCallsWindow,
      leadsByDay: days.map((day) => ({ day, leads: leadsByDay[day] || 0 })),
