const base='https://services.leadconnectorhq.com';
const token=process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB||process.env.GHL_PRIVATE_INTEGRATION_TOKEN||process.env.GHL_TOKEN;
const loc=process.env.GHL_LOCATION_ID_TJB||process.env.GHL_LOCATION_ID||'TW8JsPW5NMnA3tfK2XLn';
const h={Authorization:'Bearer '+token,Version:'2021-07-28','Content-Type':'application/json'};
const req=async(path)=>{const r=await fetch(base+path,{headers:h});const t=await r.text();let j={};try{j=t?JSON.parse(t):{}}catch{j={raw:t}};if(!r.ok) throw new Error(path+' -> '+r.status);return j;};
const toMs=v=>{if(v==null)return NaN; if(typeof v==='number') return v<1e12?v*1000:v; const p=Date.parse(v); return Number.isNaN(p)?NaN:p};
(async()=>{
 let path=`/contacts/?locationId=${loc}&limit=100`; const all=[];
 for(let i=0;i<10;i++){
  const j=await req(path); const arr=j.contacts||[]; all.push(...arr);
  if(!j.meta?.nextPageUrl) break;
  const u=new URL(j.meta.nextPageUrl); path=u.pathname+u.search;
 }
 const now=Date.now(),w1=now-7*86400000,w2=now-14*86400000;
 const counts={scorecard:0,ebook:0,course:0,lite:0,membership:0,backend:0,intensiveApplied:0,intensiveWon:0,newLead:0};
 const thisW={scorecard:0,ebook:0,course:0};
 const lastW={scorecard:0,ebook:0,course:0};
 const valueStep={};
 for(const c of all){
  const tags=(c.tags||[]).map(t=>String(t).toLowerCase()); const set=new Set(tags);
  const added=toMs(c.dateAdded||c.createdAt);
  if(set.has('scorecard-complete')||set.has('scorecard-lead')){counts.scorecard++; if(added>=w1)thisW.scorecard++; else if(added>=w2&&added<w1)lastW.scorecard++;}
  if(set.has('ebook-buyer')){counts.ebook++; if(added>=w1)thisW.ebook++; else if(added>=w2&&added<w1)lastW.ebook++;}
  if(set.has('course-buyer')){counts.course++; if(added>=w1)thisW.course++; else if(added>=w2&&added<w1)lastW.course++;}
  if(set.has('lite-buyer'))counts.lite++;
  if(set.has('membership-active'))counts.membership++;
  if(set.has('high-ticket-prospect'))counts.backend++;
  if(set.has('intensive-applied'))counts.intensiveApplied++;
  if(set.has('intensive-client'))counts.intensiveWon++;
  if(set.has('lead')||set.has('new-lead'))counts.newLead++;
  const step=String((c.customFields&&c.customFields.value_ladder_step)||c.value_ladder_step||'unknown'); valueStep[step]=(valueStep[step]||0)+1;
 }
 console.log(JSON.stringify({generatedAt:new Date().toISOString(),totalContacts:all.length,tagBased:counts,thisW,lastW,valueStep},null,2));
})();
'@ | node

