  for(const x of (m.messages||[])){
    const t=(typeof x.dateAdded==='number'?x.dateAdded:(Date.parse(x.dateAdded)||0));
    const dir=String(x.direction||x.messageDirection||'').toLowerCase();
    const mt=String(x.messageType||x.type||'unknown'); byType[mt]=(byType[mt]||0)+1;
    if(dir.includes('outbound')){ if(t>=w1) outThis++; else if(t>=w2&&t<w1) outLast++; }
  }
 }
 const cRes=await fetch(`${base}/contacts/?locationId=${loc}&limit=100`,{headers:h}).then(r=>r.json());
 for(const c of (cRes.contacts||[])){
  const updated=(Date.parse(c.dateUpdated||c.dateAdded)||0);
  const hasLeadScore=JSON.stringify(c.customFields||[]).includes('QFgiSCFczb8WbqW40f4e');
